// Règles : relance 1 à J+7 après échéance, relance 2 à J+14, relance 3 (mise en demeure amiable) à J+30.
// Anti-spam : jamais deux relances à moins de 6 jours d'intervalle (colonne derniere_relance).
const now = new Date();
const DAY = 86400000;
const out = [];
for (const item of $input.all()) {
  const f = item.json;
  if (String(f.statut || '').toLowerCase().includes('pay')) continue;   // payée -> rien
  if (!f.email || !f.date_echeance) continue;                            // données incomplètes -> rien
  const due = new Date(f.date_echeance);
  const late = Math.floor((now - due) / DAY);
  if (late < 7) continue;
  const lastR = f.derniere_relance ? new Date(f.derniere_relance) : null;
  if (lastR && (now - lastR) / DAY < 6) continue;                        // relancé récemment -> attendre
  const level = late >= 30 ? 3 : late >= 14 ? 2 : 1;
  const montant = Number(f.montant_eur || 0).toFixed(2);
  const objets = {
    1: `Facture ${f.numero_facture} — échéance dépassée`,
    2: `Relance : facture ${f.numero_facture} (${montant} €) en attente`,
    3: `Dernier rappel avant mise en demeure — facture ${f.numero_facture}`,
  };
  const corps = {
    1: `Bonjour ${f.client},\n\nSauf erreur de notre part, la facture ${f.numero_facture} de ${montant} €, échue le ${f.date_echeance}, reste en attente de règlement.\n\nSi le paiement est déjà parti, merci d'ignorer ce message. Sinon, vous trouverez la facture en pièce jointe de notre premier envoi.\n\nBien cordialement`,
    2: `Bonjour ${f.client},\n\nMalgré notre précédent message, la facture ${f.numero_facture} de ${montant} € (échue le ${f.date_echeance}) demeure impayée à ce jour (${late} jours de retard).\n\nMerci de procéder au règlement sous 7 jours, ou de nous indiquer la difficulté rencontrée — nous trouverons une solution.\n\nBien cordialement`,
    3: `Bonjour ${f.client},\n\nLa facture ${f.numero_facture} de ${montant} € est impayée depuis ${late} jours malgré nos relances.\n\nSans règlement ou réponse de votre part sous 8 jours, nous serons contraints d'engager une procédure de recouvrement. Nous préférerions sincèrement l'éviter.\n\nCordialement`,
  };
  out.push({ json: { ...f, jours_retard: late, niveau_relance: level, email_objet: objets[level], email_corps: corps[level] } });
}
return out;
